import React from "react";
import styled from "styled-components";
import { Link } from "react-router-dom";

const HeroContainer = styled.section`
  background-color: var(--background-dark);
  color: white;
  position: relative;
  overflow: hidden;
  padding: 8rem 2rem;

  @media (max-width: 768px) {
    padding: 6rem 2rem;
  }
`;

const HeroBackground = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-image: linear-gradient(rgba(0, 0, 0, 0.7), rgba(0, 0, 0, 0.7)), url(${props => props.image});
  background-size: cover;
  background-position: center;
  z-index: 0;
`;

const HeroContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  position: relative;
  z-index: 1;
  text-align: center;
`;

const HeroTitle = styled.h1`
  font-size: 3.5rem;
  margin-bottom: 1.5rem;
  font-weight: 700;

  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const HeroSubtitle = styled.p`
  font-size: 1.4rem;
  max-width: 700px;
  margin: 0 auto 3rem;
  line-height: 1.6;

  @media (max-width: 768px) {
    font-size: 1.2rem;
  }
`;

const HeroButtonContainer = styled.div`
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
`;

const PrimaryButton = styled(Link)`
  background-color: var(--primary-color);
  color: white;
  padding: 1rem 2rem;
  border-radius: 6px;
  font-weight: 500;
  font-size: 1.1rem;
  transition: background-color 0.3s ease;

  &:hover {
    background-color: var(--secondary-color);
    color: white;
  }
`;

const SecondaryButton = styled(Link)`
  background-color: transparent;
  color: white;
  padding: 1rem 2rem;
  border-radius: 6px;
  font-weight: 500;
  font-size: 1.1rem;
  border: 2px solid white;
  transition: background-color 0.3s ease, color 0.3s ease;

  &:hover {
    background-color: white;
    color: var(--text-primary);
  }
`;

const Hero = ({ 
  title = "Empowering vulnerable communities since 2016", 
  subtitle = "We work to create sustainable change through community-led initiatives focusing on youth development, gender equality, and economic empowerment.", 
  backgroundImage = "/images/hero-bg.jpg" 
}) => {
  return (
    <HeroContainer>
      <HeroBackground image={backgroundImage} />
      <HeroContent>
        <HeroTitle>{title}</HeroTitle>
        <HeroSubtitle>{subtitle}</HeroSubtitle>
        <HeroButtonContainer>
          <PrimaryButton to="/donate">Donate Now</PrimaryButton>
          <SecondaryButton to="/get-involved">Get Involved</SecondaryButton>
        </HeroButtonContainer>
      </HeroContent>
    </HeroContainer>
  );
};

export default Hero;
